import { execSync } from "child_process";
import fs from "fs";
function putText(n,s){const repo=process.env.GH_REPO,tok=process.env.GH_TOKEN;const url='https://api.github.com/repos/'+repo+'/contents/analize/'+n;let sha='';try{sha=JSON.parse(execSync('curl -s --max-time 30 -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||'';}catch(e){}const b={message:'x',branch:'main',content:Buffer.from(s,'utf8').toString('base64')};if(sha)b.sha=sha;fs.writeFileSync('/tmp/pf.json',JSON.stringify(b));execSync('curl -s --max-time 40 -X PUT -H "Authorization: Bearer '+tok+'" -d @/tmp/pf.json "'+url+'"',{encoding:'utf8'});}
const BASE='https://dev.avesa.lt';const U=process.env.WP_USER||'';const P=(process.env.WP_APP_PASS||'').replace(/\s+/g,'');
const TESTPHP="if ( ! defined('ABSPATH') ) { return; }\nadd_action('wp_loaded', function(){\n  if ( ! isset($_GET['ps_s188_test']) ) { return; }\n  if ( ($_GET['token']??'') !== 'cmplz_6680aa2a42151d54fa8d64ec' ) { return; }\n  $out = array();\n  global $wpdb;\n\n  $out['0_core_ver'] = defined('PETSHOP_CORE_VERSION') ? PETSHOP_CORE_VERSION : '?';\n  $out['0_registry'] = class_exists('Petshop_Event_Registry');\n  $out['0_emitters'] = class_exists('Petshop_Event_Emitters');\n\n  // 1. Registry \u2014 active events\n  $out['1_active_events'] = Petshop_Event_Registry::active_events();\n  $out['1_is_order_paid_canonical'] = Petshop_Event_Registry::is_canonical('order_paid');\n  $out['1_is_fake_canonical'] = Petshop_Event_Registry::is_canonical('fake_event');\n\n  // 2. Schema validation \u2014 geras order_paid payload\n  $good = array('order_id'=>1, 'order_total'=>10.0, 'order_currency'=>'EUR', 'order_items'=>array());\n  $out['2_valid_good'] = Petshop_Event_Registry::validate('order_paid', $good);\n  // Blogas \u2014 tr\u016bksta order_total + blogas currency\n  $bad = array('order_id'=>1, 'order_currency'=>'USD', 'order_items'=>array());\n  $out['2_valid_bad'] = Petshop_Event_Registry::validate('order_paid', $bad);\n\n  // 3. Registry emit \u2014 order_paid (be strict, allowlist email)\n  $r3 = Petshop_Event_Registry::emit('order_paid', 'terra@gyvunai.lt', array(\n    'order_id'=>77777, 'order_total'=>25.50, 'order_currency'=>'EUR',\n    'order_items'=>array(array('product_id'=>1,'name'=>'Test','quantity'=>1,'line_total'=>25.50))\n  ), array('event_id'=>'test_op_'.time()));\n  $out['3_emit_order_paid'] = array('ok'=>$r3['ok'], 'log_id'=>$r3['log_id']??null, 'validation'=>$r3['validation']['valid']??null);\n\n  // 4. Event log ira\u0161as\n  if(!empty($r3['log_id'])){\n    $ev = $wpdb->get_row($wpdb->prepare(\"SELECT event_name,status,email FROM {$wpdb->prefix}ps_event_log WHERE id=%d\", $r3['log_id']));\n    $out['4_event_row'] = $ev ? array('name'=>$ev->event_name,'status'=>$ev->status,'email'=>$ev->email) : 'null';\n    $wpdb->delete($wpdb->prefix.'ps_event_log', array('id'=>$r3['log_id']));\n  }\n\n  // 5. consent_changed emit per set_marketing_consent (integracija)\n  $wpdb->query(\"DELETE FROM {$wpdb->prefix}ps_consent_log WHERE email='terra@gyvunai.lt' AND source='admin'\");\n  $wpdb->query(\"DELETE FROM {$wpdb->prefix}ps_event_log WHERE event_name='consent_changed' AND email='terra@gyvunai.lt'\");\n  // Pakei\u010diam consent (turi fire'inti consent_changed event)\n  $before_count = (int)$wpdb->get_var(\"SELECT COUNT(*) FROM {$wpdb->prefix}ps_event_log WHERE event_name='consent_changed' AND email='terra@gyvunai.lt'\");\n  ps_set_marketing_consent('terra@gyvunai.lt', false, 'admin', 0);  // kei\u010diam \u012f false\n  $after_count = (int)$wpdb->get_var(\"SELECT COUNT(*) FROM {$wpdb->prefix}ps_event_log WHERE event_name='consent_changed' AND email='terra@gyvunai.lt'\");\n  $out['5_consent_event_created'] = ($after_count > $before_count);\n  $out['5_consent_event_count'] = $after_count;\n\n  // 6. WC hook'ai registruoti?\n  $out['6_wc_payment_hook'] = has_action('woocommerce_payment_complete') ? 'yes' : 'no';\n  $out['6_wc_processing_hook'] = has_action('woocommerce_order_status_processing') ? 'yes' : 'no';\n\n  // cleanup consent\n  $wpdb->query(\"DELETE FROM {$wpdb->prefix}ps_consent_log WHERE email='terra@gyvunai.lt' AND source='admin'\");\n  $wpdb->query(\"DELETE FROM {$wpdb->prefix}ps_event_log WHERE event_name='consent_changed' AND email='terra@gyvunai.lt'\");\n  $out['7_cleanup'] = 'done';\n\n  header('Content-Type: application/json; charset=utf-8');\n  echo wp_json_encode($out, JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES|JSON_PRETTY_PRINT);\n  exit;\n}, 6);";
const SCHEMAS={"shipment_returned.schema.json": "", "subscription_t5_notice.schema.json": "", "pet_profile_created.schema.json": "", "payment_failed.schema.json": "", "order_paid.schema.json": "", "consent_changed.schema.json": "", "cart_abandoned.schema.json": "", "legacy_contact_imported.schema.json": "", "subscription_t2_sms_needed.schema.json": "", "refill_due.schema.json": "", "order_shipped.schema.json": "", "pet_profile_updated.schema.json": "", "pet_reminder_due.schema.json": ""};
function api(method,path,body){const auth='-u "'+U+':'+P+'"';let cmd;if(body){fs.writeFileSync('/tmp/b.json',JSON.stringify(body));cmd='curl -s -k --max-time 90 -w "\nHTTP:%{http_code}" '+auth+' -X '+method+' -H "Content-Type: application/json" --data-binary @/tmp/b.json "'+BASE+path+'"';}else{cmd='curl -s -k --max-time 60 -w "\nHTTP:%{http_code}" '+auth+' -X '+method+' "'+BASE+path+'"';}let r;try{r=execSync(cmd,{encoding:'utf8',maxBuffer:30000000});}catch(e){r=(e.stdout||'')+'\nHTTP:TIMEOUT';}return{code:(r.match(/HTTP:(\S+)$/)||[])[1]||'?',body:r.replace(/\nHTTP:\S+$/,'')};}
function sh(c){try{return execSync(c,{encoding:'utf8',maxBuffer:30000000});}catch(e){return (e.stdout||'')+'[ERR]';}}
