    "  header('Content-Type:application/json');echo wp_json_encode($out);exit;\n" +
    "},6);";
  const c=api('POST','/wp-json/code-snippets/v1/snippets',{name:'S188 Deploy tmp',desc:'x',code:depPHP,scope:'global',active:true,priority:5});
  let sid=0;try{sid=JSON.parse(c.body).id;}catch(e){}
  execSync('sleep 2');
  L('deploy: '+sh('curl -s -k --max-time 40 "'+BASE+'/?ps_s188_dep=1&token=cmplz_6680aa2a42151d54fa8d64ec"'));
  if(sid) api('POST','/wp-json/code-snippets/v1/snippets/'+sid+'/deactivate',{});

  // 2. Reactivate core
  const actPHP = "if(!defined('ABSPATH'))return;\nadd_action('wp_loaded',function(){if(($_GET['ps_s188_act']??'')!=='1')return;if(($_GET['token']??'')!=='cmplz_6680aa2a42151d54fa8d64ec')return;if(!function_exists('activate_plugin'))require_once ABSPATH.'wp-admin/includes/plugin.php';deactivate_plugins('petshop-core/petshop-core.php');$e=activate_plugin('petshop-core/petshop-core.php');header('Content-Type:application/json');echo wp_json_encode(array('active'=>is_plugin_active('petshop-core/petshop-core.php'),'err'=>is_wp_error($e)?$e->get_error_message():null,'ver'=>defined('PETSHOP_CORE_VERSION')?PETSHOP_CORE_VERSION:'?'));exit;},6);";
  const c2=api('POST','/wp-json/code-snippets/v1/snippets',{name:'S188 Act tmp',desc:'x',code:actPHP,scope:'global',active:true,priority:5});
  let sid2=0;try{sid2=JSON.parse(c2.body).id;}catch(e){}
  execSync('sleep 2');
  L('reactivate: '+sh('curl -s -k --max-time 30 "'+BASE+'/?ps_s188_act=1&token=cmplz_6680aa2a42151d54fa8d64ec"'));
  if(sid2) api('POST','/wp-json/code-snippets/v1/snippets/'+sid2+'/deactivate',{});
  execSync('sleep 1');
  L('Home: '+sh('curl -s -k --max-time 30 -o /dev/null -w "HTTP:%{http_code}" "'+BASE+'/?nc='+Date.now()+'"'));

