  execSync('sleep 2');
  L(''); L('=== S188 TEST ==='); L(sh('curl -s -k --max-time 40 "'+BASE+'/?ps_s188_test=1&token=cmplz_6680aa2a42151d54fa8d64ec"'));
  if(sid3) api('POST','/wp-json/code-snippets/v1/snippets/'+sid3+'/deactivate',{});
  putText('s188_test.txt', out);
